class AllOne {
public:
    unordered_map<string, int> count;
    multiset<int> keys;
    multiset<int>::iterator it;

    AllOne() {

    }

    void inc(string key) {
        if (count.find(key) == count.end()) {
            keys.insert(1);
            count[key] = 1;
        } else {
            int val = count[key];
            keys.erase(keys.find(val));
            keys.insert(val + 1);
            count[key] = val + 1;
        }
    }

    void dec(string key) {
        int val = count[key];
        if (val == 1) {
            keys.erase(keys.find(1));
            count.erase(key);
        } else {
            keys.erase(keys.find(val));
            keys.insert(val - 1);
            count[key] = val - 1;
        }
    }

    string getMaxKey() {
        if (keys.empty()) return "";
        return *keys.rbegin();
    }

    string getMinKey() {
        if (keys.empty()) return "";
        return *keys.begin();
    }
};
```

